/**
 * Modular exponentiation: (base^exp) % mod
 * Assumes base, exp, and mod are BigInts.
 */
function power(base, exp, mod) {
    let res = 1n;
    base %= mod;
    while (exp > 0n) {
        if (exp % 2n === 1n) {
            res = (res * base) % mod;
        }
        base = (base * base) % mod;
        exp /= 2n;
    }
    return res;
}

function solve(nums1, nums0) {
    const MOD = 1000000007n;

    // 1. Combine segments
    let segments = [];
    const N = nums1.length;
    for (let i = 0; i < N; i++) {
        segments.push({ 
            a1: nums1[i], 
            a0: nums0[i] 
        });
    }

    // 2. Sort segments
    // Custom comparator: A comes before B if A.a1 > B.a1 OR (A.a1 == B.a1 AND A.a0 < B.a0)
    segments.sort((A, B) => {
        if (A.a1 !== B.a1) {
            // Sort descending by a1
            return B.a1 - A.a1;
        } else {
            // Sort ascending by a0
            return A.a0 - B.a0;
        }
    });

    let result = 0n;

    // 3. Iterate and calculate the resulting number modulo MOD
    for (const segment of segments) {
        const a1 = BigInt(segment.a1);
        const a0 = BigInt(segment.a0);

        // Length of the current segment
        const totalLength = a1 + a0;

        // Calculate Value(S) = (2^a1 - 1) * 2^a0 mod MOD

        // 2^a1 mod MOD
        const p1 = power(2n, a1, MOD);

        // 2^a0 mod MOD
        const p2 = power(2n, a0, MOD);

        // V_S = (p1 - 1) * p2 mod MOD
        // (p1 - 1 + MOD) % MOD handles potential underflow if p1 was 0, although p1 >= 1 here.
        const valS = (((p1 - 1n + MOD) % MOD) * p2) % MOD;

        // Calculate 2^(a1+a0) mod MOD (This is the factor by which the existing result is multiplied)
        const pTotal = power(2n, totalLength, MOD);

        // Update Result: Result_new = (Result_old * 2^L) + Value(S) mod MOD
        result = ((result * pTotal) % MOD + valS) % MOD;
    }

    // Return the final result as a standard Number type since it's guaranteed to fit within MOD < 10^9 + 7
    return Number(result);
}

