        // (2^a1 - 1) mod MOD
        // We add MOD before taking modulo to ensure positivity, although p_2a1 >= 1 here.
        let term1 = (p_2a1 - 1 + MOD) % MOD;

        // 2^a0 mod MOD
        let p_2a0 = power(2, a0);

        // V_S = (p_2a0 * term1) mod MOD
        let val_s = (p_2a0 * term1) % MOD;

        // Calculate 2^(a1+a0) mod MOD (The multiplier for the existing result)
        let p_total = power(2, total_length);

        // Update Result: Result_new = (Result_old * 2^L) + Value(S) mod MOD
