    // 1. Combine segments (a1, a0)
    let mut segments: Vec<(i64, i64)> = Vec::with_capacity(nums1.len());
    for i in 0..nums1.len() {
        segments.push((nums1[i], nums0[i]));
    }

    // 2. Sort segments
    // Sort descending by a1 (nums1), then ascending by a0 (nums0).
    segments.sort_by(|&(a1_a, a0_a), &(a1_b, a0_b)| {
        if a1_a != a1_b {
            // Descending order for a1
            a1_b.cmp(&a1_a)
